const std = @import("std");

const Kind = enum { string, number };

pub fn label(kind: Kind) []const u8 {
    return std.meta.tagToString(kind);
}

const std = @import("std");

const Kind = enum { string, number };

pub fn label(kind: Kind) []const u8 {
    return @tagName(kind);
}

const std = @import("std");

const Kind = enum { string, number };

pub fn parse(name: []const u8) !Kind {
    return std.meta.stringToEnum(Kind, name) orelse error.UnknownKind;
}
